import{_ as t,o,c as r,a3 as s}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"42. Hours Of Work","description":"","frontmatter":{"title":"42. Hours Of Work","eba":"Nurses and Midwives 2024-2028","topics":["hours","shift-work"]},"headers":[],"relativePath":"ebas/nurses-midwives/hours-of-work/42-hours-of-work.md","filePath":"ebas/nurses-midwives/hours-of-work/42-hours-of-work.md"}'),a={name:"ebas/nurses-midwives/hours-of-work/42-hours-of-work.md"};function n(i,e,p,h,l,g){return o(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="_42-hours-of-work" tabindex="-1">42. Hours Of Work <a class="header-anchor" href="#_42-hours-of-work" aria-label="Permalink to &quot;42. Hours Of Work&quot;">​</a></h1><p><strong>42.1</strong> The ordinary hours of work will be 38 or an average of 38 hours per week worked:</p><p><strong>(a)</strong> in a one week period – 38 hours worked as five shifts of not more than eight hours each; or</p><p><strong>(b)</strong> in a two week period – 76 hours worked as not more than ten shifts of not more than eight hours each; or</p><p><strong>(c)</strong> in a four week period – 152 hours worked as nineteen shifts of eight hours each;</p><p><strong>(d)</strong> in a five week period – 190 hours worked as nineteen night shifts of ten hours each; or</p><p><strong>(e)</strong> by mutual agreement:</p><p><strong>(i)</strong> any shift length or combination provided that the length of any ordinary shift will not exceed ten hours; or</p><p><strong>(ii)</strong> in shifts of up to 12 hours in accordance with a 12 hour shift agreement under clause 42.8.</p><p><strong>42.2</strong> Work for each shift will be continuous except as provided at <a href="/eba/ebas/nurses-midwives/hours-of-work/44-breaks.html">clause 44</a> (Breaks).</p><p><strong>42.3</strong> Subject to the roster provision <a href="/eba/ebas/nurses-midwives/hours-of-work/45-rosters.html">clause 45</a> (Rosters), not more than 48 ordinary hours be worked in any week.</p><p><strong>42.4</strong> The hours of work in this clause will be the maximum ordinary hours for a shift.</p><p><strong>42.5</strong> In the case of the health services or Campuses named at clause 42.6 below, or any successor or amalgamation of these health service or Campuses, hours of work for full-time and part-time Employees will be performed as follows:</p><p><strong>(a)</strong> for a shift other than a night shift, 8 hours;</p><p><strong>(b)</strong> for night shift, 10 hours; or</p><p><strong>(c)</strong> in respect to residential aged care wards/Campuses of Bendigo Health, for night shift, 9.5 hours.</p><p><strong>42.6</strong> The named health services/Campuses are:</p><p><strong>(a)</strong> Bairnsdale Regional Health Service (all Campuses);</p><p><strong>(b)</strong> Rural Northwest Health (all Campuses);</p><p><strong>(c)</strong> Otway Health (all Campuses);</p><p><strong>(d)</strong> Bendigo Health (all residential aged care wards/Campuses);</p><p><strong>(e)</strong> Maldon Health (all Campuses);</p><p><strong>(f)</strong> Benalla Health (all Campuses);</p><p><strong>(g)</strong> Djerriwarrh Health Services (all Campuses);</p><p><strong>(h)</strong> Gippsland Southern Health Service (all Campuses);</p><p><strong>(i)</strong> Hepburn Health Service (Creswick Campus);</p><p><strong>(j)</strong> Rochester and Elmore District Health Service (all Campuses);</p><p><strong>(k)</strong> Cohuna District Hospital (all Campuses);</p><p><strong>(l)</strong> Yarrawonga District Health Service (all Campuses);</p><p><strong>(m)</strong> Central Gippsland Health Service (all Campuses);</p><p><strong>(n)</strong> Maryborough District Health Service (all Campuses);</p><p><strong>(o)</strong> Heathcote Health (all Campuses);</p><p><strong>(p)</strong> Goulburn Valley Health (Tatura Campus);</p><p><strong>(q)</strong> Beechworth Health Service (all Campuses);</p><p><strong>(r)</strong> East Wimmera Health Service (St Arnaud Campus);</p><p><strong>(s)</strong> East Wimmera Health Service (Donald Campus);</p><p><strong>(t)</strong> Kilmore District Health (all Campuses);</p><p><strong>(u)</strong> Cobram District Health (all Campuses);</p><p><strong>(v)</strong> Kyneton District Health Hospital &amp; Community Care (all Campuses);</p><p><strong>(w)</strong> West Gippsland Healthcare Group;</p><p><strong>(x)</strong> Mansfield Hospital;</p><p><strong>(y)</strong> East Wimmera Health Service (Charlton, Wycheproof and Birchip Campuses);</p><p><strong>(z)</strong> Grampians Health (Edenhope and District Memorial Hospital Campus);</p><p><strong>(aa)</strong> Western District Health Service (Hamilton and Penshurst Campuses);</p><p><strong>(bb)</strong> Kerang District Health;</p><p><strong>(cc)</strong> Latrobe Regional Hospital;</p><p><strong>(dd)</strong> Alexandra District Hospital;</p><p><strong>(ee)</strong> Echuca Health (Aged Care); and</p><p><strong>(ff)</strong> Casterton Memorial Hospital.</p><p><strong>42.7</strong> Employers named at subclauses 42.6(cc), (dd), (ee) and (ff) will implement the hours of work above as follows:</p><p><strong>(a)</strong> The Employers whose Campuses are named at subclauses 42.6(cc), (dd), (ee) and (ff) will implement the hours of work as soon as practicable but not later than 1 January 2025.</p><p><strong>(b)</strong> In the event of any dispute arising regarding Employee support for the new hours of work at subclauses 42.6(cc), (dd), (ee) and (ff), the matter will be dealt</p><p>with in accordance with <a href="/eba/ebas/nurses-midwives/classification-staffing/93-proposals-to-vary-specific-matters.html">clause 93.8</a> (Implementation of a non-complying proposal).</p><p><strong>(c)</strong> Nothing in this clause 42.7 requires the implementation of the hours at clause</p><p><strong>42.5</strong> where the Employee does not work on a 24/7 ward.</p><p><strong>(d)</strong> The implementation of the new hours of work is not to affect an Employee&#39;s normal or customary working days or shift arrangements, except to the extent of the shift duration.</p><p><strong>(e)</strong> An Employer will not require an Employee to reduce their contracted hours directly or indirectly as a result of the change to hours of work.</p><p><strong>(f)</strong> The process of implementation of the hours of work arrangements at clause 42.5 must also comply with <a href="/eba/ebas/nurses-midwives/consultation-disputes/11-consultation.html">clause 11</a> (Consultation).</p><p><strong>(g)</strong> Notwithstanding anything else in this clause, in the event an Employer, because of recruitment difficulties, is unable to implement the hours of work arrangement by the date specified in clause 42.7 despite taking all reasonable and practical steps to comply, the Employer will notify the Unions and the VHIA in writing. Either the Unions or the VHIA may refer the matter to the Commission who may do one or more of the following:</p><p><strong>(i)</strong> extend the implementation date by up to six (6) months; and/or</p><p><strong>(ii)</strong> require the Employer to take steps towards implementation in accordance with such timetables as the Commission determines are just and fair.</p><p><strong>42.8</strong> 12 Hour Shift Agreement</p><p><strong>(a)</strong> An Employer has a 12 Hour Shift Agreement where:</p><p><strong>(i)</strong> the Employer had, at the time this Agreement commenced, an existing 12 Hour Shift Agreement reduced to writing and signed by the Employer party and the ANMF;</p><p><strong>(ii)</strong> the Employer was, at the time this Agreement commenced, conducting a trial for 12 hour shifts. A trial under this clause requires written agreement with the ANMF;</p><p><strong>(iii)</strong> during the operation of this Agreement, a new trial for 12 hour shifts is, by agreement with the ANMF, conducted; or</p><p><strong>(iv)</strong> following a trial, any agreed outcome for an ongoing 12 hour shift agreement will be reduced to writing and signed by the Employer party and the ANMF.</p><p><strong>(b)</strong> A 12 Hour Shift agreement that commences after this Agreement comes into operation will be implemented in accordance with <a href="/eba/ebas/nurses-midwives/classification-staffing/93-proposals-to-vary-specific-matters.html">clause 93.8</a> (Implementation of a non-complying proposal) of this Agreement.</p><p><strong>(c)</strong> Any 12 hour shift trial or agreement must allow, as a minimum, for 2 meal breaks per 12 hour shift - one unpaid 30 minute meal break and one 20 minute paid meal break and three 10 minute paid tea breaks.</p><p><strong>(d)</strong> A 12 hour shift trial or agreement may be terminated either:</p><p><strong>(i)</strong> in the manner provided in the shift trial or agreement; or</p><p><strong>(ii)</strong> in the case of the Employer, following consultation in accordance with <a href="/eba/ebas/nurses-midwives/consultation-disputes/11-consultation.html">clause 11</a> of this Agreement (Consultation) and, where relevant, <a href="/eba/ebas/nurses-midwives/consultation-disputes/12-redundancy-and-associated-entitlements.html">clause 12</a> (Redundancy and Associated Entitlements).</p>',72)])])}const c=t(a,[["render",n]]);export{u as __pageData,c as default};
